  <svg viewBox="0 0 700 420" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="30" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Três Sinais de Liquidez, uma Reação Fraca do Bitcoin</text>
    <g font-family="sans-serif">
      <text x="20" y="62" fill="#a1a1aa" font-size="13">M2 Global (4 grandes bancos centrais, anual, fev)</text>
